// Step 1 — widen: nullable, applied with: npx prisma migrate dev --name add_country_nullable
model User {
  id      Int     @id @default(autoincrement())
  email   String  @unique
  name    String
  country String?
}

-- Step 2 — fill: npx prisma migrate dev --create-only --name backfill_country
-- then write this by hand into the generated migration.sql and apply with: npx prisma migrate dev
UPDATE "User" SET "country" = 'VN' WHERE "country" IS NULL;

// Step 3 — tighten: required, applied with: npx prisma migrate dev --name require_country
// generated SQL: ALTER TABLE "User" ALTER COLUMN "country" SET NOT NULL;
model User {
  id      Int    @id @default(autoincrement())
  email   String @unique
  name    String
  country String
}

