solutionCodeJson.code:
// Step 1 — additive: npx prisma migrate dev --name add_editor_role
// generated: ALTER TYPE "Role" ADD VALUE 'EDITOR';
enum Role {
  USER
  ADMIN
  EDITOR
}

model User {
  id    Int    @id @default(autoincrement())
  email String @unique
  role  Role   @default(USER)
}

-- Step 2 — move every row off the value being retired.
-- npx prisma migrate dev --create-only --name move_users_to_editor
UPDATE "User" SET "role" = 'EDITOR' WHERE "role" = 'USER';

// Step 3 — destructive, safe only because no row holds USER any more.
// npx prisma migrate dev --name drop_user_role
// Prisma recreates the type: CREATE TYPE "Role_new" AS ENUM ('ADMIN', 'EDITOR'); ... DROP TYPE "Role";
enum Role {
  ADMIN
  EDITOR
}

model User {
  id    Int    @id @default(autoincrement())
  email String @unique
  role  Role   @default(EDITOR)
}

